module RefModule(
    input [7:0] data_i,
    input [2:0] shift_i,
    output [2:0] data_o
    );reg [15:0] unused_tmp;
   always @*
      case (shift_i)
         3'b000: unused_tmp = data_i;
         3'b001: unused_tmp = data_i << 1;
         3'b010: unused_tmp = data_i << 2;
         3'b011: unused_tmp = data_i << 3;
         3'b100: unused_tmp = data_i << 4;
         3'b101: unused_tmp = data_i << 5;
         3'b110: unused_tmp = data_i << 6;
         default: unused_tmp = data_i << 7;
      endcase
	assign data_o = unused_tmp[7:5];endmodule
